import * as React from "react"
import { ArrowUp, ArrowDown, Minus } from "lucide-react"
import { format, isToday, isYesterday, differenceInDays, parseISO } from "date-fns"
import { cn } from "@/lib/utils"

export interface MetricCardProps {
  label: string
  value: string | number
  unit?: string
  source: string
  dateStr: string
  isPrimary?: boolean
  change?: { value: number; formatted: string; direction: "up" | "down" | "neutral" }
  changeLabel?: string
}

export function MetricCard({
  label,
  value,
  unit,
  source,
  dateStr,
  isPrimary = false,
  change,
  changeLabel = "vs yesterday",
}: MetricCardProps) {
  const date = parseISO(dateStr)
  const daysOld = differenceInDays(new Date(), date)
  const isStale = daysOld >= 2

  const getMetricDateLabel = (dateStr: string) => {
    const date = parseISO(dateStr)
    if (isToday(date)) return "Today"
    if (isYesterday(date)) return "Yesterday"
    return format(date, "MMM d")
  }

  const getChangeColor = (direction: "up" | "down" | "neutral") => {
    if (direction === "up") return "text-emerald-600"
    if (direction === "down") return "text-amber-600"
    return "text-gray-400"
  }

  const changeColor = change ? getChangeColor(change.direction) : "text-gray-400"

  return (
    <div
      className={cn(
        "flex flex-col rounded-xl border bg-white shadow-sm transition-all h-full",
        isPrimary ? "border-gray-200 p-5 md:p-6" : "border-gray-100 bg-gray-50/50 p-4",
        isStale && "opacity-60"
      )}
    >
      <div className="flex justify-between items-start mb-3">
        <span
          className={cn(
            "font-semibold text-gray-500 uppercase tracking-wider truncate pr-2",
            isPrimary ? "text-xs" : "text-[10px]"
          )}
        >
          {label}
        </span>
        <span className="text-[10px] text-gray-400 font-medium uppercase flex-shrink-0">
          {source}
        </span>
      </div>

      <div className="mt-auto">
        <div className="flex items-baseline gap-1 mb-1.5">
          <span
            className={cn(
              "font-bold text-gray-900 tracking-tight",
              isPrimary ? "text-3xl md:text-4xl" : "text-2xl"
            )}
          >
            {value}
          </span>
          {unit && <span className="text-sm text-gray-500 font-medium">{unit}</span>}
        </div>

        {change && (
          <div className="flex items-center gap-1.5 mb-2">
            <div className={cn("flex items-center gap-0.5 font-semibold text-xs", changeColor)}>
              {change.direction === "up" && <ArrowUp size={12} strokeWidth={3} />}
              {change.direction === "down" && <ArrowDown size={12} strokeWidth={3} />}
              {change.direction === "neutral" && <Minus size={12} strokeWidth={3} />}
              <span>{change.formatted}</span>
            </div>
            <span className="text-[10px] text-gray-400 font-normal whitespace-nowrap">
              {changeLabel}
            </span>
          </div>
        )}

        <div className="flex items-center gap-1.5 pt-2 border-t border-gray-100 mt-1">
          <span
            className={cn(
              "text-[10px] font-medium uppercase tracking-wide",
              isStale ? "text-amber-600" : "text-gray-400"
            )}
          >
            {getMetricDateLabel(dateStr)}
          </span>
          {isStale && <span className="w-1.5 h-1.5 rounded-full bg-amber-500" />}
        </div>
      </div>
    </div>
  )
}
